from django import forms
from django.core.exceptions import ValidationError
from django.forms import CompositeFieldValidator
from django.test import SimpleTestCase


class CompositeFieldValidatorTests(SimpleTestCase):
    """Tests for the CompositeFieldValidator class."""

    def test_validator_instantiation(self):
        """Test that CompositeFieldValidator can be instantiated."""

        def dummy_validator(cleaned_data):
            pass

        validator = CompositeFieldValidator(
            dummy_validator, ["field1", "field2"], "Test message"
        )

        self.assertEqual(validator.function, dummy_validator)
        self.assertEqual(validator.field_names, ["field1", "field2"])
        self.assertEqual(validator.message, "Test message")

    def test_validator_is_callable(self):
        """Test that CompositeFieldValidator is callable."""

        def dummy_validator(cleaned_data):
            pass

        validator = CompositeFieldValidator(dummy_validator, ["field1"], "Error")
        self.assertTrue(callable(validator))

    def test_basic_validation_passes(self):
        """Test that validation passes when condition is met."""

        def validate_dates(cleaned_data):
            start = cleaned_data.get("start_date")
            end = cleaned_data.get("end_date")
            if start and end and end <= start:
                raise ValidationError("End date must be after start date.")

        class DateForm(forms.Form):
            start_date = forms.DateField()
            end_date = forms.DateField()
            composite_validators = [
                CompositeFieldValidator(validate_dates, ["start_date", "end_date"])
            ]

        form = DateForm({"start_date": "2024-01-01", "end_date": "2024-01-02"})
        self.assertTrue(form.is_valid())

    def test_basic_validation_fails(self):
        """Test that validation fails when condition is not met."""

        def validate_dates(cleaned_data):
            start = cleaned_data.get("start_date")
            end = cleaned_data.get("end_date")
            if start and end and end <= start:
                raise ValidationError("End date must be after start date.")

        class DateForm(forms.Form):
            start_date = forms.DateField()
            end_date = forms.DateField()
            composite_validators = [
                CompositeFieldValidator(validate_dates, ["start_date", "end_date"])
            ]

        form = DateForm({"start_date": "2024-01-02", "end_date": "2024-01-01"})
        self.assertFalse(form.is_valid())
        self.assertIn("start_date", form.errors)

    def test_validation_error_attached_to_first_field(self):
        """Test that validation error is attached to the first field."""

        def validate_emails(cleaned_data):
            email1 = cleaned_data.get("email1")
            email2 = cleaned_data.get("email2")
            if email1 and email2 and email1 != email2:
                raise ValidationError("Emails do not match.")

        class EmailForm(forms.Form):
            email1 = forms.EmailField()
            email2 = forms.EmailField()
            composite_validators = [
                CompositeFieldValidator(validate_emails, ["email1", "email2"])
            ]

        form = EmailForm(
            {"email1": "test1@example.com", "email2": "test2@example.com"}
        )
        self.assertFalse(form.is_valid())
        self.assertIn("email1", form.errors)
        self.assertNotIn("email2", form.errors)

