        """Test that multiple composite validators can be used."""

        def validate_ages(cleaned_data):
            min_age = cleaned_data.get("min_age")
            max_age = cleaned_data.get("max_age")
            if min_age and max_age and min_age > max_age:
                raise ValidationError("Min age must be less than max age.")

        def validate_dates(cleaned_data):
            start = cleaned_data.get("start_date")
            end = cleaned_data.get("end_date")
            if start and end and start >= end:
                raise ValidationError("Start date must be before end date.")

        class FilterForm(forms.Form):
            min_age = forms.IntegerField()
            max_age = forms.IntegerField()
            start_date = forms.DateField()
            end_date = forms.DateField()
            composite_validators = [
                CompositeFieldValidator(validate_ages, ["min_age", "max_age"]),
                CompositeFieldValidator(validate_dates, ["start_date", "end_date"]),
            ]

        # All valid
        form = FilterForm(
            {
                "min_age": "18",
                "max_age": "65",
                "start_date": "2024-01-01",
                "end_date": "2024-12-31",
            }
        )
        self.assertTrue(form.is_valid())

        # Age validation fails
        form = FilterForm(
            {
                "min_age": "65",
                "max_age": "18",
                "start_date": "2024-01-01",
                "end_date": "2024-12-31",
            }
        )
        self.assertFalse(form.is_valid())
        self.assertIn("min_age", form.errors)

        # Date validation fails
        form = FilterForm(
            {
                "min_age": "18",
                "max_age": "65",
                "start_date": "2024-12-31",
                "end_date": "2024-01-01",
            }
        )
        self.assertFalse(form.is_valid())
        self.assertIn("start_date", form.errors)

