        form = ComplexForm({"field1": "bad", "field2": "bad"})
        self.assertFalse(form.is_valid())
        self.assertIn("field1", form.errors)
        self.assertIn("field2", form.errors)

        # Only one field invalid
        form = ComplexForm({"field1": "bad", "field2": "good"})
        self.assertFalse(form.is_valid())
        self.assertIn("field1", form.errors)
        self.assertNotIn("field2", form.errors)

